const { createClient } = require('@supabase/supabase-js');
const xlsx = require('xlsx');

const supabase = createClient(
  'https://ebktoazswvtqsjrjryqk.supabase.co',
  'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImVia3RvYXpzd3Z0cXNqcmpyeXFrIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzM5MDM2NzIsImV4cCI6MjA4OTQ3OTY3Mn0.a3kFa8JOBlvZ-PSMWEcIDQKLLPDrXbPf4qTRptWvki8'
);

(async () => {
  // 1. 원본 데이터 가져오기
  const { data: original, error } = await supabase
    .from('set_composition')
    .select('*')
    .ilike('set_barcode', 'LE103%')
    .order('set_barcode');

  if (error) {
    console.error('Error:', error);
    return;
  }

  // 2. 수정된 파일 읽기
  const workbook = xlsx.readFile('/Users/jooho/Downloads/시어서커_세트구성_수정.xlsx');
  const sheet = workbook.Sheets[workbook.SheetNames[0]];
  const modified = xlsx.utils.sheet_to_json(sheet);

  // 3. 비교를 위한 키 생성
  const makeKey = (item) => {
    const barcode = item.set_barcode || item['세트바코드'] || '';
    const compBarcode = item.component_barcode || item['구성품바코드'] || '';
    return \`\${barcode}|\${compBarcode}\`;
  };

  const originalMap = new Map(original.map(item => [makeKey(item), item]));
  const modifiedMap = new Map(modified.map(item => [makeKey(item), item]));

  console.log('📊 원본: ' + original.length + '개');
  console.log('📊 수정본: ' + modified.length + '개');
  console.log('');

  // 4. 변경점 찾기
  const added = [];
  const deleted = [];
  const changed = [];

  // 추가된 항목
  for (const [key, item] of modifiedMap) {
    if (!originalMap.has(key)) {
      added.push(item);
    }
  }

  // 삭제된 항목
  for (const [key, item] of originalMap) {
    if (!modifiedMap.has(key)) {
      deleted.push(item);
    }
  }

  // 변경된 항목 (수량 등)
  for (const [key, modItem] of modifiedMap) {
    if (originalMap.has(key)) {
      const origItem = originalMap.get(key);
      const origQty = origItem.quantity;
      const modQty = modItem['수량'] || modItem.quantity;

      if (origQty !== modQty) {
        changed.push({
          set_barcode: modItem['세트바코드'],
          component_name: modItem['구성품명'],
          component_barcode: modItem['구성품바코드'],
          old_quantity: origQty,
          new_quantity: modQty
        });
      }
    }
  }

  console.log('=== 변경 사항 ===');
  console.log('');

  if (added.length > 0) {
    console.log('✅ 추가된 구성품: ' + added.length + '개');
    added.forEach(item => {
      console.log('  + [' + item['세트바코드'] + '] ' + item['구성품명'] + ' (' + item['구성품바코드'] + ') x' + item['수량']);
    });
    console.log('');
  }

  if (deleted.length > 0) {
    console.log('❌ 삭제된 구성품: ' + deleted.length + '개');
    deleted.forEach(item => {
      console.log('  - [' + item.set_barcode + '] ' + item.component_name + ' (' + item.component_barcode + ') x' + item.quantity);
    });
    console.log('');
  }

  if (changed.length > 0) {
    console.log('🔄 수량 변경: ' + changed.length + '개');
    changed.forEach(item => {
      console.log('  ~ [' + item.set_barcode + '] ' + item.component_name + ': ' + item.old_quantity + ' → ' + item.new_quantity);
    });
    console.log('');
  }

  if (added.length === 0 && deleted.length === 0 && changed.length === 0) {
    console.log('변경 사항이 없습니다.');
  }
})();
"

