'use client'

import { useState, useEffect, useMemo } from 'react'
import { Button, Card, Badge } from '@/components/ui'
import ExcelDownloadButton from '@/components/ExcelDownloadButton'
import { supabase } from '@/lib/supabase'
import * as XLSX from 'xlsx'

interface ShipmentData {
  order_code: string
  order_memo: string
  distributor: string
  sku: string
  product_name: string
  quantity: number
  courier: string
  tracking_no: string
}

interface DailyStats {
  upload_date: string
  total_orders: number
  total_quantity: number
}

type ViewType = 'daily' | 'weekly' | 'monthly'

export default function ShipmentPage() {
  const [file, setFile] = useState<File | null>(null)
  const [parsedData, setParsedData] = useState<ShipmentData[]>([])
  const [isUploading, setIsUploading] = useState(false)
  const [todayStats, setTodayStats] = useState<DailyStats | null>(null)
  const [weekStats, setWeekStats] = useState<DailyStats | null>(null)
  const [monthStats, setMonthStats] = useState<DailyStats | null>(null)
  const [recentDates, setRecentDates] = useState<DailyStats[]>([])
  const [viewType, setViewType] = useState<ViewType>('daily')

  // 오늘 날짜
  const today = new Date().toISOString().split('T')[0]
  const currentMonth = new Date().getMonth() + 1 // 1-12

  // 이번 주 월요일
  const getThisMonday = () => {
    const date = new Date()
    const day = date.getDay()
    const diff = date.getDate() - day + (day === 0 ? -6 : 1)
    return new Date(date.setDate(diff)).toISOString().split('T')[0]
  }

  // 이번 달 1일
  const getThisMonthStart = () => {
    const date = new Date()
    return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-01`
  }

  // 통계 불러오기
  useEffect(() => {
    fetchStats()
  }, [])

  // 주간별로 그룹화 (월요일 기준)
  const getWeeklyStats = (dailyStats: DailyStats[]) => {
    const weeklyMap = new Map<string, { total_orders: number, total_quantity: number }>()

    dailyStats.forEach(stat => {
      const date = new Date(stat.upload_date)
      const day = date.getDay()
      const diff = date.getDate() - day + (day === 0 ? -6 : 1) // 월요일로 조정
      const monday = new Date(date.setDate(diff))
      const weekKey = monday.toISOString().split('T')[0]

      if (!weeklyMap.has(weekKey)) {
        weeklyMap.set(weekKey, { total_orders: 0, total_quantity: 0 })
      }

      const weekData = weeklyMap.get(weekKey)!
      weekData.total_orders += stat.total_orders
      weekData.total_quantity += stat.total_quantity
    })

    return Array.from(weeklyMap.entries())
      .map(([week, data]) => ({
        upload_date: week,
        total_orders: data.total_orders,
        total_quantity: data.total_quantity
      }))
      .sort((a, b) => b.upload_date.localeCompare(a.upload_date))
  }

  // 월별로 그룹화
  const getMonthlyStats = (dailyStats: DailyStats[]) => {
    const monthlyMap = new Map<string, { total_orders: number, total_quantity: number }>()

    dailyStats.forEach(stat => {
      const monthKey = stat.upload_date.substring(0, 7) // YYYY-MM

      if (!monthlyMap.has(monthKey)) {
        monthlyMap.set(monthKey, { total_orders: 0, total_quantity: 0 })
      }

      const monthData = monthlyMap.get(monthKey)!
      monthData.total_orders += stat.total_orders
      monthData.total_quantity += stat.total_quantity
    })

    return Array.from(monthlyMap.entries())
      .map(([month, data]) => ({
        upload_date: month,
        total_orders: data.total_orders,
        total_quantity: data.total_quantity
      }))
      .sort((a, b) => b.upload_date.localeCompare(a.upload_date))
  }

  // 현재 뷰에 맞는 데이터 가져오기
  const getDisplayData = () => {
    switch (viewType) {
      case 'weekly':
        return getWeeklyStats(recentDates)
      case 'monthly':
        return getMonthlyStats(recentDates)
      default:
        return recentDates
    }
  }

  const displayData = getDisplayData()

  // 엑셀 다운로드용 데이터
  const excelData = useMemo(() => {
    const viewLabel = viewType === 'daily' ? '일별' : viewType === 'weekly' ? '주간별' : '월별'
    return displayData.map(stat => ({
      [`${viewLabel === '주간별' ? '주간(월요일)' : viewLabel === '월별' ? '월' : '날짜'}`]: stat.upload_date,
      '출고건수': stat.total_orders,
      '상품수량': stat.total_quantity
    }))
  }, [displayData, viewType])

  const fetchStats = async () => {
    try {
      // 전체 날짜별 통계 - SQL 뷰 사용
      const { data: statsData, error: statsError } = await supabase
        .from('daily_shipment_stats_view')
        .select('*')
        .order('upload_date', { ascending: false })

      if (!statsError && statsData) {
        setRecentDates(statsData as DailyStats[])

        // 뷰 데이터로 금일/금주/금월 통계 계산
        const thisMonday = getThisMonday()
        const thisMonthStart = getThisMonthStart()

        // 금일 통계
        const todayStat = statsData.find(s => s.upload_date === today)
        if (todayStat) {
          setTodayStats({
            upload_date: today,
            total_orders: todayStat.total_orders,
            total_quantity: todayStat.total_quantity
          })
        } else {
          setTodayStats({ upload_date: today, total_orders: 0, total_quantity: 0 })
        }

        // 금주 통계 (월요일부터)
        const weekData = statsData.filter(s => s.upload_date >= thisMonday)
        const weekOrders = weekData.reduce((sum, s) => sum + s.total_orders, 0)
        const weekQty = weekData.reduce((sum, s) => sum + s.total_quantity, 0)
        setWeekStats({
          upload_date: thisMonday,
          total_orders: weekOrders,
          total_quantity: weekQty
        })

        // 금월 통계
        const monthData = statsData.filter(s => s.upload_date >= thisMonthStart)
        const monthOrders = monthData.reduce((sum, s) => sum + s.total_orders, 0)
        const monthQty = monthData.reduce((sum, s) => sum + s.total_quantity, 0)
        setMonthStats({
          upload_date: thisMonthStart,
          total_orders: monthOrders,
          total_quantity: monthQty
        })
      }
    } catch (error) {
      console.error('통계 조회 실패:', error)
    }
  }

  // 파일 선택
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0]
    if (selectedFile) {
      setFile(selectedFile)
      parseExcel(selectedFile)
    }
  }

  // 오더코드에서 날짜 추출 (O20260323-00297 → 2026-03-23)
  const extractDateFromOrderCode = (orderCode: string): string => {
    try {
      // O 다음 8자리 추출 (YYYYMMDD)
      const dateStr = orderCode.substring(1, 9)
      const year = dateStr.substring(0, 4)
      const month = dateStr.substring(4, 6)
      const day = dateStr.substring(6, 8)
      return `${year}-${month}-${day}`
    } catch (error) {
      console.error('날짜 추출 실패:', error)
      return new Date().toISOString().split('T')[0] // 실패 시 오늘 날짜
    }
  }

  // 엑셀 파싱
  const parseExcel = (file: File) => {
    // 파일 유효성 검증
    if (!file) {
      alert('파일을 선택해주세요')
      return
    }
    if (file.size === 0) {
      alert('빈 파일입니다. 파일을 다시 확인해주세요')
      return
    }

    // 확장자 검증
    const validExtensions = ['.xlsx', '.xls', '.csv']
    const isValidExt = validExtensions.some(ext => file.name.toLowerCase().endsWith(ext))
    if (!isValidExt) {
      alert('엑셀 파일(.xlsx, .xls) 또는 CSV 파일만 업로드 가능합니다')
      return
    }

    const reader = new FileReader()

    reader.onerror = () => {
      console.error('파일 읽기 실패')
      alert('파일을 읽을 수 없습니다. 파일이 손상되었거나 권한이 없습니다.')
    }

    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer)

        if (data.length === 0) {
          alert('파일 내용이 비어있습니다')
          return
        }

        // 파일 헤더 검증
        // .xlsx (ZIP): 50 4B (PK)
        // .xls (BIFF): D0 CF 11 E0
        const isZip = data[0] === 0x50 && data[1] === 0x4B
        const isBiff = data[0] === 0xD0 && data[1] === 0xCF
        const isCSV = file.name.toLowerCase().endsWith('.csv')

        if (!isZip && !isBiff && !isCSV) {
          alert('올바른 엑셀 파일이 아닙니다.\n\n파일이 손상되었거나 다른 형식입니다.\n엑셀에서 파일을 열어 .xlsx로 다시 저장 후 시도해주세요.')
          return
        }

        const workbook = XLSX.read(data, {
          type: 'array',
          cellDates: false,
          cellNF: false,
          cellHTML: false,
        })

        if (!workbook.SheetNames || workbook.SheetNames.length === 0) {
          alert('엑셀 파일에 시트가 없습니다')
          return
        }

        const sheetName = workbook.SheetNames[0]
        const worksheet = workbook.Sheets[sheetName]
        const jsonData = XLSX.utils.sheet_to_json(worksheet, { defval: '' }) as any[]

        if (jsonData.length === 0) {
          alert('파일에 데이터가 없습니다')
          return
        }

        const parsed: ShipmentData[] = jsonData.map((row) => ({
          order_code: row['오더코드'] || '',
          order_memo: row['상품별 메모1'] || '',
          distributor: row['발주 타입'] || '',
          sku: row['고유코드'] || '',
          product_name: row['판매상품명'] || '',
          quantity: parseInt(row['수량']) || 0,
          courier: row['택배사'] || '',
          tracking_no: row['송장번호'] || ''
        }))

        setParsedData(parsed)
      } catch (error: any) {
        console.error('엑셀 파싱 실패:', error)

        // 에러 종류별 메시지
        let message = '엑셀 파일 읽기에 실패했습니다.'
        const errMsg = error?.message || ''

        if (errMsg.includes('Bad uncompressed size')) {
          message = '파일이 손상되었거나 잘못된 형식입니다.\n\n해결 방법:\n1. 엑셀에서 파일을 다시 열어서 "다른 이름으로 저장" → .xlsx로 저장\n2. 파일을 다시 다운로드'
        } else if (errMsg.includes('Unsupported')) {
          message = '지원되지 않는 파일 형식입니다. .xlsx 또는 .xls 파일을 사용해주세요.'
        } else if (errMsg.includes('password')) {
          message = '암호로 보호된 파일은 열 수 없습니다. 암호를 해제 후 다시 시도해주세요.'
        }

        alert(message)
      }
    }

    reader.readAsArrayBuffer(file)
  }

  // 전체 데이터 삭제
  const handleDeleteAll = async () => {
    if (!confirm('⚠️ 정말 모든 데이터를 삭제하시겠습니까?\n\n이 작업은 되돌릴 수 없습니다!')) {
      return
    }

    if (!confirm('다시 한 번 확인합니다.\n\n모든 출고 데이터를 삭제하시겠습니까?')) {
      return
    }

    try {
      const { error } = await supabase
        .from('daily_shipment_data')
        .delete()
        .neq('id', 0) // 모든 데이터 삭제

      if (error) {
        console.error('삭제 실패:', error)
        alert('삭제 중 오류가 발생했습니다: ' + error.message)
        return
      }

      alert('모든 데이터가 삭제되었습니다!')

      // 통계 새로고침
      await fetchStats()
    } catch (error) {
      console.error('삭제 중 오류:', error)
      alert('삭제 중 오류가 발생했습니다.')
    }
  }

  // 날짜별 데이터 삭제
  const handleDeleteByDate = async (date: string) => {
    if (!confirm(`${date}의 모든 데이터를 삭제하시겠습니까?`)) {
      return
    }

    try {
      const { error } = await supabase
        .from('daily_shipment_data')
        .delete()
        .eq('upload_date', date)

      if (error) {
        console.error('삭제 실패:', error)
        alert('삭제 중 오류가 발생했습니다: ' + error.message)
        return
      }

      alert(`${date} 데이터가 삭제되었습니다!`)

      // 통계 새로고침
      await fetchStats()
    } catch (error) {
      console.error('삭제 중 오류:', error)
      alert('삭제 중 오류가 발생했습니다.')
    }
  }

  // 데이터 저장
  const handleSave = async () => {
    if (parsedData.length === 0) {
      alert('업로드할 데이터가 없습니다.')
      return
    }

    setIsUploading(true)
    try {
      // 각 오더코드에서 날짜 추출
      const dataToInsert = parsedData.map(item => ({
        ...item,
        upload_date: extractDateFromOrderCode(item.order_code)
      }))

      // 업로드할 데이터의 고유 날짜 추출
      const uploadDates = [...new Set(dataToInsert.map(item => item.upload_date))]

      // 중복 날짜 확인
      const { data: existingDates, error: checkError } = await supabase
        .from('daily_shipment_data')
        .select('upload_date')
        .in('upload_date', uploadDates)

      if (checkError) {
        console.error('중복 확인 실패:', checkError)
        alert('중복 확인 중 오류가 발생했습니다.')
        setIsUploading(false)
        return
      }

      // 중복된 날짜가 있는지 확인
      if (existingDates && existingDates.length > 0) {
        const duplicateDates = [...new Set(existingDates.map(d => d.upload_date))].sort()
        alert(`⚠️ 이미 업로드된 날짜가 있습니다:\n\n${duplicateDates.join('\n')}\n\n중복된 날짜의 데이터를 먼저 삭제한 후 다시 업로드해주세요.`)
        setIsUploading(false)
        return
      }

      // 중복이 없으면 저장 진행
      const { error } = await supabase
        .from('daily_shipment_data')
        .insert(dataToInsert)

      if (error) {
        console.error('저장 실패:', error)
        alert('저장 중 오류가 발생했습니다: ' + error.message)
        return
      }

      alert(`${parsedData.length}건의 데이터가 저장되었습니다!`)

      // 초기화
      setFile(null)
      setParsedData([])

      // 통계 새로고침
      await fetchStats()
    } catch (error) {
      console.error('저장 중 오류:', error)
      alert('저장 중 오류가 발생했습니다.')
    } finally {
      setIsUploading(false)
    }
  }

  return (
    <main className="min-h-screen bg-background">
      <div className="max-w-7xl mx-auto px-8 py-10">
        {/* 헤더 */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold tracking-tight text-text-primary mb-2">
            QC 일일 출고관리 (3PL)
          </h1>
          <p className="text-sm text-text-muted">
            판매 데이터 업로드 시 자동으로 연동되는 출고 현황을 확인하세요
          </p>
        </div>

        {/* 통계 카드 */}
        <div className="grid md:grid-cols-3 gap-6 mb-8">
          {/* 금일 */}
          <Card className="p-6 bg-gradient-to-br from-blue-50 to-white border-2 border-blue-200">
            <div className="flex items-center justify-between mb-4">
              <p className="text-sm font-semibold text-text-tertiary">📅 금일</p>
              <div className="text-3xl">📦</div>
            </div>
            <div>
              <p className="text-2xl font-bold text-brand-primary mb-1">
                {todayStats?.total_orders || 0}<span className="text-sm ml-1">건</span>
              </p>
              <p className="text-xl font-semibold text-green-600">
                {todayStats?.total_quantity || 0}<span className="text-xs ml-1">개</span>
              </p>
            </div>
          </Card>

          {/* 금주 */}
          <Card className="p-6 bg-gradient-to-br from-purple-50 to-white border-2 border-purple-200">
            <div className="flex items-center justify-between mb-4">
              <p className="text-sm font-semibold text-text-tertiary">📊 금주</p>
              <div className="text-3xl">📈</div>
            </div>
            <div>
              <p className="text-2xl font-bold text-purple-600 mb-1">
                {weekStats?.total_orders || 0}<span className="text-sm ml-1">건</span>
              </p>
              <p className="text-xl font-semibold text-purple-500">
                {weekStats?.total_quantity || 0}<span className="text-xs ml-1">개</span>
              </p>
            </div>
          </Card>

          {/* 이번 달 */}
          <Card className="p-6 bg-gradient-to-br from-orange-50 to-white border-2 border-orange-200">
            <div className="flex items-center justify-between mb-4">
              <p className="text-sm font-semibold text-text-tertiary">📈 {currentMonth}월</p>
              <div className="text-3xl">📋</div>
            </div>
            <div>
              <p className="text-2xl font-bold text-orange-600 mb-1">
                {monthStats?.total_orders || 0}<span className="text-sm ml-1">건</span>
              </p>
              <p className="text-xl font-semibold text-orange-500">
                {monthStats?.total_quantity || 0}<span className="text-xs ml-1">개</span>
              </p>
            </div>
          </Card>
        </div>

        {/* 자동 연동 안내 */}
        <Card className="p-6 mb-8 bg-gradient-to-br from-blue-50 to-white border-2 border-blue-200">
          <div className="flex items-start gap-4">
            <div className="text-4xl">ℹ️</div>
            <div className="flex-1">
              <h2 className="text-xl font-bold text-blue-900 mb-3">📊 자동 연동 안내</h2>
              <div className="space-y-2 text-sm text-blue-800">
                <p className="font-semibold">
                  출고관리 데이터는 <span className="text-blue-600">판매 데이터 업로드</span>에서 자동으로 연동됩니다.
                </p>
                <div className="bg-white rounded-lg p-4 border border-blue-200">
                  <p className="font-semibold mb-2">📤 업로드 방법:</p>
                  <ol className="list-decimal list-inside space-y-1 text-blue-700">
                    <li><strong>판매현황 &gt; 출고 데이터 업로드</strong> 메뉴로 이동</li>
                    <li><strong>투민글로벌</strong> 창고 선택</li>
                    <li>발주조회 엑셀 파일 업로드</li>
                    <li>자동으로 일별현황 + 출고관리에 동시 저장됨</li>
                  </ol>
                </div>
                <p className="text-xs text-blue-600 mt-3">
                  ✅ 세트 상품 자동 분해 | ✅ 수량 일치 보장 | ✅ 중복 방지
                </p>
              </div>
            </div>
          </div>
        </Card>

        {/* 날짜별 통계 */}
        {recentDates.length > 0 && (
          <Card className="p-6">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-bold text-text-primary">출고 현황</h2>
              <div className="flex items-center gap-3">
                <ExcelDownloadButton
                  data={excelData}
                  filename="3PL_출고현황"
                  sheetName="출고현황"
                />
              </div>
            </div>

            {/* 뷰 타입 선택 탭 */}
            <div className="flex gap-2 mb-4 border-b border-border">
              <button
                onClick={() => setViewType('daily')}
                className={`px-4 py-2 font-medium transition-colors ${
                  viewType === 'daily'
                    ? 'text-brand-primary border-b-2 border-brand-primary'
                    : 'text-text-tertiary hover:text-text-secondary'
                }`}
              >
                📅 일별
              </button>
              <button
                onClick={() => setViewType('weekly')}
                className={`px-4 py-2 font-medium transition-colors ${
                  viewType === 'weekly'
                    ? 'text-brand-primary border-b-2 border-brand-primary'
                    : 'text-text-tertiary hover:text-text-secondary'
                }`}
              >
                📊 주간별
              </button>
              <button
                onClick={() => setViewType('monthly')}
                className={`px-4 py-2 font-medium transition-colors ${
                  viewType === 'monthly'
                    ? 'text-brand-primary border-b-2 border-brand-primary'
                    : 'text-text-tertiary hover:text-text-secondary'
                }`}
              >
                📈 월별
              </button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead className="bg-background-muted border-b border-border">
                  <tr>
                    <th className="px-4 py-3 text-left font-semibold text-text-tertiary">
                      {viewType === 'daily' ? '날짜' : viewType === 'weekly' ? '주간 (월요일 기준)' : '월'}
                    </th>
                    <th className="px-4 py-3 text-right font-semibold text-text-tertiary">출고건수</th>
                    <th className="px-4 py-3 text-right font-semibold text-text-tertiary">상품수량</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border">
                  {displayData.map((stat) => (
                    <tr key={stat.upload_date} className="hover:bg-background-hover">
                      <td className="px-4 py-3 text-text-primary font-medium">
                        {viewType === 'daily' && stat.upload_date === today ? (
                          <span className="flex items-center gap-2">
                            {stat.upload_date}
                            <Badge variant="primary" size="sm">오늘</Badge>
                          </span>
                        ) : viewType === 'weekly' ? (
                          `${stat.upload_date} 주`
                        ) : (
                          stat.upload_date
                        )}
                      </td>
                      <td className="px-4 py-3 text-right text-brand-primary font-semibold">
                        {stat.total_orders}건
                      </td>
                      <td className="px-4 py-3 text-right text-green-600 font-semibold">
                        {stat.total_quantity}개
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </Card>
        )}
      </div>
    </main>
  )
}

import { supabase } from '@/lib/supabase'
import ClientPage from './ClientPage'
