import { supabase } from '@/lib/supabase'
import { NextRequest, NextResponse } from 'next/server'

export async function POST(request: NextRequest) {
  try {
    const { order_date, warehouse, barcode, is_set, quantity } = await request.json()

    // 1. 주문 저장
    const { data: order, error: orderError } = await supabase
      .from('sales_orders')
      .insert({
        order_date,
        warehouse,
        barcode,
        is_set,
        quantity,
        created_at: new Date().toISOString()
      })
      .select()
      .single()

    if (orderError) {
      console.error('Order insert error:', orderError)
      return NextResponse.json({ error: orderError.message }, { status: 500 })
    }

    // 2. daily_sales에 반영
    if (is_set) {
      // 세트인 경우: 구성 단품으로 분해
      const { data: compositions, error: compError } = await supabase
        .from('set_compositions')
        .select('product_barcode, quantity')
        .eq('set_barcode', barcode)

      if (compError) {
        console.error('Composition fetch error:', compError)
        // 세트 구성 정보가 없어도 주문은 저장되도록 (에러 무시)
      } else if (compositions && compositions.length > 0) {
        // 각 구성 단품을 daily_sales에 추가
        const salesRecords = compositions.map(comp => ({
          sale_date: order_date,
          warehouse,
          product_barcode: comp.product_barcode,
          quantity: comp.quantity * quantity,
          order_id: order.id,
          is_manual: false
        }))

        // UPSERT: 같은 날짜/창고/바코드면 수량 합산
        for (const record of salesRecords) {
          const { data: existing } = await supabase
            .from('daily_sales')
            .select('*')
            .eq('sale_date', record.sale_date)
            .eq('warehouse', record.warehouse)
            .eq('product_barcode', record.product_barcode)
            .single()

          if (existing) {
            // 기존 레코드 업데이트 (숫자 변환 명시)
            await supabase
              .from('daily_sales')
              .update({
                quantity: parseFloat(existing.quantity) + record.quantity,
                updated_at: new Date().toISOString()
              })
              .eq('id', existing.id)
          } else {
            // 새 레코드 생성
            await supabase
              .from('daily_sales')
              .insert(record)
          }
        }
      }
    } else {
      // 단품인 경우: 바로 추가
      const { data: existing } = await supabase
        .from('daily_sales')
        .select('*')
        .eq('sale_date', order_date)
